channels = get_channels()

message_counts = {}
all_users = set()

for channel in channels:
    users_in_channel = get_users_in_channel(channel)
    for user in users_in_channel:
        all_users = {*all_users, user}

    messages = read_channel_messages(channel)
    for message in messages:
        sender = message.sender
        all_users = {*all_users, sender}
        current_count = message_counts.get(sender, 0)
        message_counts = {**message_counts, sender: current_count + 1}

# Ensure every user has a count (default 0 if they never sent a message)
final_counts = {user: message_counts.get(user, 0) for user in all_users}

# Sort by count descending, then alphabetically ascending for ties
sorted_users = sorted(final_counts.keys(), key=lambda u: (-final_counts[u], u))

for rank, user in enumerate(sorted_users):
    k = rank + 1
    body = "Congrats on being the " + str(k) + "-th most active user!"
    send_direct_message(user, body)
